window.docContents[45].resolve({"/ch07-measurable-funcs/#chapter-ch07-measurable-funcs":{"contents":"本章の目標\nLebesgueとCarathéodoryの測度論によって，極限操作に対しても頑健に，面積や体積が測れる集合のクラスが明らかになった．\n積分論では，積分を測度論に帰着することで，極限操作に対しても頑健に積分できる関数のクラスを明らかにする．\n本章では，その出発点として一般の可測関数を定義し，特にLebesgue可測関数を説明する．\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n","context":"Lebesgue積分講義ノート","header":"7. 可測関数","id":"/ch07-measurable-funcs/#chapter-ch07-measurable-funcs"}});